def pct(vals,p):
    vals=sorted(vals); return vals[int((len(vals)-1)*p)]

def choose_offer(e):
    d={p:pr for p,pr in e['offers']}
    g=e['group']
    if 'A' in d:
        # A quality is now often sufficient and much cheaper; some still choose B/C for quality.
        if g=='D_E02': probs=[0.62,0.28,0.10]
        elif g=='E3': probs=[0.55,0.32,0.13]
        elif g=='E1': probs=[0.76,0.19,0.05]
        elif g=='E2': probs=[0.25,0.55,0.20]
        elif g=='D_E07': probs=[0.42,0.40,0.18]
        elif g=='D_E08': probs=[0.45,0.35,0.20]
        elif g=='D_E09': probs=[0.58,0.30,0.12]
        else: probs=[0.50,0.35,0.15]
        u=random.random()
        if u<probs[0] and 'A' in d: return 'A',d['A']
        if u<probs[0]+probs[1] and 'B' in d: return 'B',d['B']
        if 'C' in d: return 'C',d['C']
        if 'B' in d: return 'B',d['B']
        return 'A',d['A']
    if 'B' in d and 'C' in d:
        pc=0.20
        if d.get('C',999)<=49: pc=0.28
        if d.get('C',999)>=79: pc=0.16
        if e['group']=='D_E02': pc=0.16
        return ('C',d['C']) if random.random()<pc else ('B',d['B'])
    if 'B' in d: return 'B',d['B']
    if 'C' in d: return 'C',d['C']
    return 'A',19.0

def initial_ent_events(days):
    ev=[]
    for e in open_ents:
        age=DAY-e['first_day']
        p=max(0.0005,min(0.55,random.gauss(e['mu'],e['mu']*0.55+0.018)))
        if random.random()<p:
            if e['group'] in ('D_E09','E1'): delay=max(2,int(random.gauss(8,5)))
            elif e['group']=='D_E02': delay=max(2,int(random.gauss(10,6)))
            elif e['group'] in ('D_E07','D_E08','E2'): delay=max(4,int(random.gauss(17,9)))
            elif age>55: delay=max(4,int(random.gauss(16,11)))
            elif age>20: delay=max(7,int(random.gauss(24,13)))
            else: delay=max(10,int(random.gauss(35,17)))
            day=DAY+delay
            if day<=DAY+days:
                plan,price=choose_offer(e)
                ev.append({'day':day,'seats':e['seats'],'plan':plan,'price':price,'mod':day%30,'group':e['group']})
    return ev

